// Restore research query after Telegram message was sent
// (Telegram node only outputs its API response, not the original data)
const triggerData = $('Telegram Trigger').item.json;
const chatId = triggerData.message.chat.id;

let query = '';
let inputType = 'text';

// Try to get query from voice transcription path
try {
  const voiceItem = $('Set Voice Query').item;
  if (voiceItem && voiceItem.json && voiceItem.json.query) {
    query = voiceItem.json.query;
    inputType = 'voice';
  }
} catch(e) {}

// Fall back to text path
if (!query) {
  try {
    const textItem = $('Set Text Query').item;
    if (textItem && textItem.json && textItem.json.query) {
      query = textItem.json.query;
      inputType = 'text';
    }
  } catch(e) {}
}

// Last resort: read directly from trigger
if (!query) {
  query = triggerData.message.text || 'Unable to extract query.';
}

return [{ json: { query, chat_id: chatId, input_type: inputType } }];

