// Split long research reports into Telegram-compatible chunks (4096 char limit)
const output = $json.output || 'Research completed but no output was generated.';
const chatId = $('Telegram Trigger').item.json.message.chat.id;
const MAX_LENGTH = 4000; // buffer below Telegram's 4096 hard limit

if (output.length <= MAX_LENGTH) {
  return [{ json: { text: output, chat_id: chatId, part: 1, total_parts: 1 } }];
}

// Split at natural paragraph boundaries
const chunks = [];
let remaining = output;

while (remaining.length > 0) {
  if (remaining.length <= MAX_LENGTH) {
    chunks.push(remaining.trim());
    break;
  }

  // Prefer splitting at double newline (paragraph boundary)
  let splitAt = remaining.lastIndexOf('\n\n', MAX_LENGTH);

  // Fall back to single newline
  if (splitAt <= 200) {
    splitAt = remaining.lastIndexOf('\n', MAX_LENGTH);
  }

  // Last resort: hard cut
  if (splitAt <= 200) {
    splitAt = MAX_LENGTH;
  }

  chunks.push(remaining.substring(0, splitAt).trim());
  remaining = remaining.substring(splitAt).trim();
}

const totalParts = chunks.length;

return chunks.map((chunk, index) => ({
  json: {
    text: totalParts > 1
      ? `📄 *Part ${index + 1} of ${totalParts}*\n\n${chunk}`
      : chunk,
    chat_id: chatId,
    part: index + 1,
    total_parts: totalParts
  }
}));
